"""
Monitor access patterns to detect digital divide signals in agent deployment.
Track whether certain demographic or geographic groups have systematically
lower access or systematically worse outcomes.
"""

from dataclasses import dataclass
from collections import defaultdict
import statistics


@dataclass
class AccessEvent:
    user_id: str
    region: str            # anonymised regional tag
    device_tier: str       # "low_end", "mid_range", "high_end"
    session_duration_s: float
    task_completion: bool
    latency_ms: float


def compute_access_equity_report(events: list[AccessEvent]) -> dict:
    by_region: dict[str, list[AccessEvent]] = defaultdict(list)
    by_device: dict[str, list[AccessEvent]] = defaultdict(list)

    for e in events:
        by_region[e.region].append(e)
        by_device[e.device_tier].append(e)

    def completion_rate(evts):
        return sum(1 for e in evts if e.task_completion) / max(1, len(evts))

    def median_latency(evts):
        return statistics.median(e.latency_ms for e in evts)

    report = {
        "by_region": {
            region: {
                "event_count": len(evts),
                "completion_rate": completion_rate(evts),
                "median_latency_ms": median_latency(evts),
            }
            for region, evts in by_region.items()
        },
        "by_device_tier": {
            tier: {
                "event_count": len(evts),
                "completion_rate": completion_rate(evts),
                "median_latency_ms": median_latency(evts),
            }
            for tier, evts in by_device.items()
        },
    }

    # Flag equity concerns
    completion_rates = [v["completion_rate"] for v in report["by_region"].values()]
    if max(completion_rates) - min(completion_rates) > 0.15:
        report["equity_alert"] = "Completion rate gap > 15% across regions"

    return report
